  ('social-worker-moex-01542', 'social-worker', 'social-worker-moex-108-0e79f916', 'sub-social-worker-01', NULL, 'single_choice', '青少年睡眠逐漸受到重視，針對青少年睡眠的敘述，下列何者錯誤？', '["全美睡眠基金會研究發現青少年每晚所需的睡眠時間大約是8小時以上", "睡眠與學業和健康沒有關聯性", "青少年的睡眠模式與需求受到青春期性荷爾蒙的影響", "睡眠不足可能會出現類似過動症的癥狀"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:09+00:00", "source_pdf_sha1": "225c0ce9caca", "answer_pdf_sha1": "7f33815a6b91", "source_family": "moex-gov-tw", "moex": {"exam_code": "108020", "c": "107", "s": "0605", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "人類行為與社會環境", "year": "108", "exam_name": "108年第一次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試", "original_question_number": 28, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-01543', 'social-worker', 'social-worker-moex-108-0e79f916', 'sub-social-worker-01', NULL, 'single_choice', '有關受暴婦女的敘述，下列何者正確？', '["受暴婦女並沒有傷得那麼嚴重", "施暴及其他虐待只是偶發，並沒有經常發生", "婦女會待在這樣的家庭中，表示她們對暴力行為心甘情願", "婦女受暴不只發生在低社經家庭中"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:09+00:00", "source_pdf_sha1": "225c0ce9caca", "answer_pdf_sha1": "7f33815a6b91", "source_family": "moex-gov-tw", "moex": {"exam_code": "108020", "c": "107", "s": "0605", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "人類行為與社會環境", "year": "108", "exam_name": "108年第一次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試", "original_question_number": 29, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-01544', 'social-worker', 'social-worker-moex-108-0e79f916', 'sub-social-worker-01', NULL, 'single_choice', '符合傳統性別角色刻板印象的女性至少會面臨四種劣勢，下列何者錯誤？', '["即使女性在外工作，還是被期待做大部分的家事與照顧小孩", "來自男性的價值往往會否定女人的容貌與外表之重要性", "對女性傳統角色的要求與限制會帶來潛在壓力", "教育系統對女性似乎有不同看法，也不如對男性來得積極正面"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:09+00:00", "source_pdf_sha1": "225c0ce9caca", "answer_pdf_sha1": "7f33815a6b91", "source_family": "moex-gov-tw", "moex": {"exam_code": "108020", "c": "107", "s": "0605", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "人類行為與社會環境", "year": "108", "exam_name": "108年第一次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試", "original_question_number": 30, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-01545', 'social-worker', 'social-worker-moex-108-0e79f916', 'sub-social-worker-01', NULL, 'single_choice', '有關性別種族主義（gender racism）理論之敘述，下列何者錯誤？', '["它是衝突論的一個變異觀點", "該理論係基於有色婦女壓迫的經驗，並指涉種族主義與性別歧視主義交叉互動與雙重結合之影響", "該理論強調兩個議題：社會互動在降低種族與族群敵意上扮演重要角色，以及種族與族群是如 何被社會建構的", "該理論的意涵是：社會中的婦女地位之研究必須將個別種族與族群分開來探討"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:09+00:00", "source_pdf_sha1": "225c0ce9caca", "answer_pdf_sha1": "7f33815a6b91", "source_family": "moex-gov-tw", "moex": {"exam_code": "108020", "c": "107", "s": "0605", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "人類行為與社會環境", "year": "108", "exam_name": "108年第一次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試", "original_question_number": 31, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-01546', 'social-worker', 'social-worker-moex-108-0e79f916', 'sub-social-worker-01', NULL, 'single_choice', '有關衝突論的階層化觀點之敘述，下列何者錯誤？', '["社會階層不僅阻礙社會與個人發展，也反映支配階層的社會權力慾望", "衝突論在解釋階層對社會運作過程之意義時，主要是將韋伯（Weber）的觀點延伸與擴大", "階層化基礎只是經濟資源控制與分配的呈現", "當權威關係形成階層化時，支配階層即獲得合法權力以強迫低下階層成員順從"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:09+00:00", "source_pdf_sha1": "225c0ce9caca", "answer_pdf_sha1": "7f33815a6b91", "source_family": "moex-gov-tw", "moex": {"exam_code": "108020", "c": "107", "s": "0605", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "人類行為與社會環境", "year": "108", "exam_name": "108年第一次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試", "original_question_number": 32, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-01547', 'social-worker', 'social-worker-moex-108-0e79f916', 'sub-social-worker-01', NULL, 'single_choice', '政府會以對抗與消滅貧窮為社會福利目標。有關造成貧窮的因素，是因社會人群藉由學習與分享 所得的生活模式，是屬於下列貧窮的那一個因素？', '["個人", "結構", "次文化", "社會"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:09+00:00", "source_pdf_sha1": "225c0ce9caca", "answer_pdf_sha1": "7f33815a6b91", "source_family": "moex-gov-tw", "moex": {"exam_code": "108020", "c": "107", "s": "0605", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "人類行為與社會環境", "year": "108", "exam_name": "108年第一次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試", "original_question_number": 33, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-01548', 'social-worker', 'social-worker-moex-108-0e79f916', 'sub-social-worker-01', NULL, 'single_choice', '社會成員在同一社會階層從一個位置轉換到另一個位置，例如：從公關部經理調任人事部經理。 屬於那一個概念？', '["垂直流動", "水平流動", "向上流動", "向下流動"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:09+00:00", "source_pdf_sha1": "225c0ce9caca", "answer_pdf_sha1": "7f33815a6b91", "source_family": "moex-gov-tw", "moex": {"exam_code": "108020", "c": "107", "s": "0605", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "人類行為與社會環境", "year": "108", "exam_name": "108年第一次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試", "original_question_number": 34, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-01549', 'social-worker', 'social-worker-moex-108-0e79f916', 'sub-social-worker-01', NULL, 'single_choice', '解決貧窮問題的當務之急是消除貧窮污名，除非我們讓窮人相信他們並非一輩子注定活在窮困 中，否則，就不會有正面的改變。屬於那一個理論的主張？', '["功能論", "衝突論", "互動論", "社會交換論"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:09+00:00", "source_pdf_sha1": "225c0ce9caca", "answer_pdf_sha1": "7f33815a6b91", "source_family": "moex-gov-tw", "moex": {"exam_code": "108020", "c": "107", "s": "0605", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "人類行為與社會環境", "year": "108", "exam_name": "108年第一次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試", "original_question_number": 35, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-01550', 'social-worker', 'social-worker-moex-108-0e79f916', 'sub-social-worker-01', NULL, 'single_choice', '在青春期階段，與父母分離的過程具有四個元素，下列何者錯誤？', '["生活功能獨立", "態度獨立", "財務獨立", "衝突獨立"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:09+00:00", "source_pdf_sha1": "225c0ce9caca", "answer_pdf_sha1": "7f33815a6b91", "source_family": "moex-gov-tw", "moex": {"exam_code": "108020", "c": "107", "s": "0605", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "人類行為與社會環境", "year": "108", "exam_name": "108年第一次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試", "original_question_number": 36, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL)
